'use strict';
// Threat Analysis Engine — Offensive Wing
// Generated by Aether on 2026-06-09T16:07:31.980Z
const EventEmitter = require('events');

class ThreatAnalyzer extends EventEmitter {
  constructor() {
    super();
    this.threats = [];
    this.signatures = this._loadSignatures();
  }

  analyze(data) {
    const findings = [];
    for (const sig of this.signatures) {
      if (sig.pattern.test(JSON.stringify(data))) {
        const threat = { id: Date.now(), severity: sig.severity, type: sig.type, description: sig.description, timestamp: new Date().toISOString() };
        findings.push(threat);
        this.threats.push(threat);
        this.emit('threat', threat);
      }
    }
    return findings;
  }

  _loadSignatures() {
    return [
      { type: 'sql-injection', severity: 'critical', pattern: /(UNION|SELECT|DROP)s+/i, description: 'SQL injection detected' },
      { type: 'xss', severity: 'high', pattern: /<script[s>]/i, description: 'XSS payload detected' },
      { type: 'path-traversal', severity: 'high', pattern: /\.\.[/\\]/, description: 'Directory traversal' },
      { type: 'brute-force', severity: 'medium', pattern: /failed.*login/i, description: 'Brute-force attempt' },
    ];
  }

  getSummary() {
    const bySeverity = { critical: 0, high: 0, medium: 0, low: 0 };
    this.threats.forEach((t) => bySeverity[t.severity] = (bySeverity[t.severity] || 0) + 1);
    return { total: this.threats.length, bySeverity };
  }
}

module.exports = ThreatAnalyzer;